xpath.script:
                document.addEventListener('DOMContentLoaded', function() {
                    // Only run on /my page
                    if (window.location.pathname === '/my' || window.location.pathname === '/my/') {
                        // Find the container where cards are
                        var addressCard = document.querySelector('a[href="/my/security"]');
                        if (addressCard) {
                            var parentRow = addressCard.closest('.row');
                            if (parentRow) {
                                // Create new card HTML
                                var newCard = document.createElement('div');
                                newCard.className = 'col-lg-6 mb-3';
                                newCard.innerHTML = `








Cập nhật thông tin cá nhân

Upload tài liệu và cập nhật hồ sơ của bạn


                `;
                                parentRow.insertBefore(newCard, addressCard.closest('.col-lg-6'));
                            }
                        }
                    }
                });
